#!/usr/bin/env node
// TTADK Telemetry Hook for Claude Code
//
// Auto-generated by ttadk/core plugin. Do not edit manually.
//
// Claude Code UserPromptSubmit hook.
// Reads the hook payload from stdin and forwards it to ttadk _track.
// This script runs asynchronously (configured via async:true in hooks.json)
// and DOES NOT affect Claude Code's response behavior.
//
// Cross-platform replacement for ttadk-track-claude.sh.
// Requires Node.js (guaranteed available as a ttadk dependency).
//
// Windows note: do NOT spawn('ttadk.cmd') with shell:false — Node cannot
// execute .cmd directly. Use cmd.exe /c with a fixed command string, and
// keep the child attached (not detached) so Claude's async hook does not pop a new console.
// See: https://nodejs.org/api/child_process.html#spawning-bat-and-cmd-files-on-windows
'use strict';

const { spawn } = require('child_process');

const TRACK_EVENT = 'ttadk_claude_prompt';
/** Internal safety exit; hooks.json timeout should be higher (15s). */
const SAFETY_TIMEOUT_MS = 10000;

/**
 * Resolve how to launch `ttadk _track` without shell true or detached true.
 * @param {NodeJS.Platform} [platform]
 * @param {NodeJS.ProcessEnv} [env]
 */
function resolveTrackSpawn(platform = process.platform, env = process.env) {
  const baseOptions = {
    detached: false,
    stdio: ['pipe', 'ignore', 'ignore'],
    shell: false,
  };

  if (platform === 'win32') {
    return {
      command: env.ComSpec || 'cmd.exe',
      // Fixed string only — never interpolate user/prompt input into the command line.
      args: ['/d', '/s', '/c', `ttadk _track ${TRACK_EVENT}`],
      options: {
        ...baseOptions,
        windowsHide: true,
      },
    };
  }

  return {
    command: 'ttadk',
    args: ['_track', TRACK_EVENT],
    options: baseOptions,
  };
}

/**
 * Forward stdin payload to ttadk _track once, wait for child close/error, exit 0.
 * Never writes to stdout/stderr. Failures are silent.
 *
 * @param {Buffer|string} input
 * @param {object} [deps]
 * @returns {Promise<number>} always 0
 */
function forwardPayload(input, deps = {}) {
  const spawnFn = deps.spawn || spawn;
  const platform = deps.platform || process.platform;
  const env = deps.env || process.env;
  const setTimeoutFn = deps.setTimeout || setTimeout;
  const clearTimeoutFn = deps.clearTimeout || clearTimeout;

  const payload = Buffer.isBuffer(input) ? input : Buffer.from(input);

  return new Promise((resolve) => {
    let settled = false;
    const finish = () => {
      if (settled) return;
      settled = true;
      clearTimeoutFn(timer);
      resolve(0);
    };

    const timer = setTimeoutFn(finish, deps.safetyTimeoutMs ?? SAFETY_TIMEOUT_MS);

    try {
      const { command, args, options } = resolveTrackSpawn(platform, env);
      const child = spawnFn(command, args, options);

      child.on('error', () => finish());
      child.on('close', () => finish());

      if (child.stdin) {
        child.stdin.on('error', () => {});
        // Wait for close/error — do NOT process.exit immediately after end().
        child.stdin.end(payload);
      } else {
        finish();
      }
    } catch {
      finish();
    }
  });
}

function main() {
  const chunks = [];
  process.stdin.on('data', (chunk) => {
    chunks.push(Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk));
  });
  process.stdin.on('end', () => {
    // Isolation experiment (Windows): set TTADK_TRACK_ISOLATION=1 so the hook
    // only drains stdin and exits — no ttadk child. If a console still pops,
    // the cause is Claude Code's command-hook process creation (upstream),
    // not this script's spawn options. Do not switch to HTTP hooks lightly:
    // Claude HTTP hooks are sync and add per-prompt latency/failure surface.
    // See: https://github.com/anthropics/claude-code/issues/61051
    if (process.env.TTADK_TRACK_ISOLATION === '1') {
      process.exit(0);
      return;
    }
    forwardPayload(Buffer.concat(chunks)).then((code) => {
      process.exit(code);
    });
  });
  process.stdin.on('error', () => process.exit(0));
}

if (require.main === module) {
  main();
}
